export const category = "java_advanced_choice";
export const questions = [{"category":"java_advanced_choice","difficulty":"medium","type":"choice","title":"Volatile 的内存语义","content":"在 Java 内存模型中，对 volatile 变量的写操作具有什么内存语义？","answer":"A) 只刷新写线程的本地缓存","correct":"B","hints":["volatile 写 = 释放语义（Release），volatile 读 = 获取语义（Acquire）","volatile 禁止指令重排序（LoadLoad/StoreStore/LoadStore/StoreLoad 屏障）"],"tags":["java"],"options":["A) 只刷新写线程的本地缓存","B) 将更改立即刷新到主内存，并使其他线程的该变量缓存失效","C) 只对当前线程可见","D) 在单核 CPU 上不生效"],"id":2607},{"category":"java_advanced_choice","difficulty":"medium","type":"choice","title":"ScheduledThreadPoolExecutor 的核心","content":"ScheduledThreadPoolExecutor 使用什么数据结构来管理待执行的定时任务？","answer":"A) 红黑树","correct":"C","hints":["DelayQueue 内部使用小顶堆（PriorityQueue）实现，堆顶是最早到期的任务","每次从队列中取任务时检查堆顶任务的延迟时间是否已到"],"tags":["java"],"options":["A) 红黑树","B) 哈希表","C) 延迟队列（DelayQueue/DelayedWorkQueue）","D) 循环数组"],"id":2608},{"category":"java_advanced_choice","difficulty":"medium","type":"choice","title":"ForkJoinPool 的工作窃取调度","content":"ForkJoinPool 的工作窃取（Work-Stealing）算法中，每个工作线程从哪里获取任务？","answer":"A) 只从全局共享队列获取","correct":"C","hints":["工作线程用自己的 LIFO 栈（尾部），窃取时从对方队列的头部（FIFO）","这种设计减少窃取时的竞争（窃取者和所有者操作队列的不同端）"],"tags":["java"],"options":["A) 只从全局共享队列获取","B) 优先处理自己的双向队列的头部任务，窃取时从其他线程队列的尾部获取","C) 优先处理自己的双向队列的尾部任务，窃取时从其他线程队列的头部获取","D) 所有线程从同一个优先队列中竞争获取任务"],"id":2609},{"category":"java_advanced_choice","difficulty":"medium","type":"choice","title":"ThreadLocal 的内存泄漏","content":"ThreadLocal 内存泄漏的根本原因是什么？","answer":"A) ThreadLocalMap 的 Entry 强引用 Key","correct":"B","hints":["Entry 继承 WeakReference<ThreadLocal>，Key 是弱引用可被 GC 回收","但 Value 是强引用且 Entry 在线程池的线程中长期存活 → Value 泄漏"],"tags":["java"],"options":["A) ThreadLocalMap 的 Entry 强引用 Key","B) ThreadLocalMap 的 Entry 的 Key 是 WeakReference，但 Value 是强引用","C) 线程池中的线程永远不会被回收","D) ThreadLocal 变量本身不会被 GC 回收"],"id":2610},{"category":"java_advanced_choice","difficulty":"medium","type":"choice","title":"AQS 独占锁的获取流程","content":"在 AQS（AbstractQueuedSynchronizer）中，独占锁（如 ReentrantLock）的获取流程第一步是什么？","answer":"A) 直接进入等待队列","correct":"B","hints":["AQS 先尝试 CAS 获取锁（快速路径），失败后才进入等待队列","这种设计减少了锁竞争不激烈时的入队开销"],"tags":["java"],"options":["A) 直接进入等待队列","B) 尝试 CAS 获取锁（state 0→1）","C) 阻塞当前线程","D) 检查等待队列是否为空"],"id":2611},{"category":"java_advanced_choice","difficulty":"hard","type":"choice","title":"Java 模块化 exports 和 opens","content":"在 Java 模块化系统中，关于 exports 和 opens 的区别，正确的是？","options":["A) exports 允许其他模块反射访问私有成员","B) opens 允许编译期访问类型，反射时仍需检查","C) exports 允许编译期访问类型，反射时仍受限","D) exports 和 opens 功能完全相同"],"answer":"C","hints":["exports 允许编译期访问公共类型，反射时仍受限；opens 允许反射深度访问"],"tags":["Java","模块化","JPMS"],"id":2612},{"category":"java_advanced_choice","difficulty":"hard","type":"choice","title":"G1 GC 混合回收","content":"关于 G1 GC 的 Mixed GC 阶段，以下说法正确的是？","options":["A) Mixed GC 只回收年轻代","B) Mixed GC 同时回收年轻代和部分老年代（CSet 包含一定比例的老年代 Region）","C) Mixed GC 相当于 Full GC","D) Mixed GC 在 G1 的整个生命周期持续运行"],"answer":"B","hints":["Mixed GC 在初始标记和并发标记之后进行，CSet 同时包含年轻代和老年代 Region"],"tags":["JVM","G1","GC"],"id":2613},{"category":"java_advanced_choice","difficulty":"hard","type":"multiple_choice","title":"Java 17 新特性","content":"以下哪些特性是 Java 17（LTS）引入或正式确定的？（多选）","options":["A) 密封类（Sealed Classes）","B) 模式匹配 for switch（正式特性）","C) 记录类（Records）转为正式特性","D) 文本块（Text Blocks）转为正式特性","E) 虚拟线程（Virtual Threads）","F) 外部函数与内存 API（Foreign Function & Memory API）孵化"],"answer":"A","hints":["Java 17 正式确定了密封类。Record 和 Text Block 在 Java 16 已正式化。模式匹配 switch 在 Java 17 是预览。虚拟线程在 Java 21 正式化。选择仅 A"],"tags":["Java","版本","新特性"],"id":2614},{"category":"java_advanced_choice","difficulty":"medium","type":"choice","title":"Java Switch 表达式","content":"关于 Java 14+ 的 switch 表达式，以下说法错误的是？","options":["A) switch 表达式可以用箭头语法 -> 代替冒号","B) switch 表达式可以使用 yield 返回值","C) 箭头语法不会穿透（fall-through）","D) switch 表达式只能用于枚举类型"],"answer":"D","hints":["switch 表达式支持 int、String、枚举以及任意类型（模式匹配 switch）"],"tags":["Java","switch","表达式"],"id":2615},{"category":"java_advanced_choice","difficulty":"hard","type":"choice","title":"JVM 即时编译 OSR","content":"关于 JVM 即时编译（JIT）的栈上替换（OSR，On-Stack Replacement），说法正确的是？","options":["A) OSR 将正在执行的热点方法替换为编译后的版本，无需等待方法返回","B) OSR 只在方法调用时触发","C) OSR 编译模式与标准 C2 编译完全相同","D) OSR 只能用于 C1 编译"],"answer":"A","hints":["OSR 用于长运行循环中的方法——当循环体达到编译阈值时，在循环回边处跳转到编译后代码"],"tags":["JVM","JIT","OSR"],"id":2616},{"category":"java_advanced_choice","difficulty":"medium","type":"choice","title":"G1GC与ZGC核心区别","content":"关于G1GC和ZGC两款低延迟垃圾收集器的对比，以下描述哪一项是错误的？","options":["A) ZGC的最大暂停时间目标通常远低于G1GC，可达毫秒级","B) G1GC基于Region分代收集，ZGC基于染色指针和读屏障实现并发","C) ZGC在JDK 21中引入了分代模式（Generational ZGC），进一步提升性能","D) G1GC使用标记-整理算法不产生内存碎片，ZGC使用标记-复制算法会产生碎片"],"answer":"D","hints":["G1GC可能退化到Full GC","染色指针是ZGC的核心创新","ZGC标记-复制在Region级别操作"],"tags":["G1GC","ZGC","GC","pause time","JVM调优"],"id":2627},{"category":"java_advanced_choice","difficulty":"hard","type":"choice","title":"Happens-Before关系判定","content":"假设线程A执行：x = 1; synchronized(lock) { flag = true; }\n线程B执行：synchronized(lock) { if(flag) { int r = x; } }\n其中x和flag初始值分别为0和false。以下关于happens-before关系的描述哪项是正确的？","options":["A) 线程A中x=1与flag=true之间不存在happens-before关系，因此线程B中r不一定为1","B) synchronized块的解锁与加锁构成happens-before关系，线程B一定看到x=1","C) 由于flag不是volatile，线程B不一定能看到flag=true，但看到后一定能看到x=1","D) 程序顺序规则保证x=1 happens-before flag=true，管程锁定规则保证解锁happens-before后续加锁，传递性保证r=1"],"answer":"D","hints":["程序顺序规则作用于单线程内","解锁和加锁构成happens-before","happens-before具有传递性"],"tags":["JMM","happens-before","synchronized","可见性"],"id":2628},{"category":"java_advanced_choice","difficulty":"medium","type":"choice","title":"synchronized的可重入性","content":"以下关于synchronized关键字可重入性的描述，哪一项是正确的？","options":["A) synchronized不支持可重入，同一个线程重复持有同一把锁会导致死锁","B) synchronized支持可重入，每个锁关联持有线程和计数器，重入时递增退出时递减","C) synchronized的可重入性只对同一个方法有效，跨方法调用不适用","D) synchronized的可重入性仅在同步代码块中有效，同步方法不支持重入"],"answer":"B","hints":["考虑子类调用父类synchronized方法","每个锁对象对应一个Monitor","计数器归零时才真正释放锁"],"tags":["synchronized","reentrant","monitor","锁"],"id":2629},{"category":"java_advanced_choice","difficulty":"hard","type":"choice","title":"volatile的内存可见性保证","content":"以下关于volatile关键字的描述，哪一项是错误的？","options":["A) volatile变量写操作会插入StoreLoad屏障，强制将写缓冲刷新到主存","B) volatile变量的读操作会令当前CPU缓存行失效，强制从主存读取最新值","C) volatile可以保证复合操作如count++的原子性","D) volatile禁止了JIT编译器对相关指令的重排序优化"],"answer":"C","hints":["count++是读改写的三步非原子操作","屏障保证可见性但不保证互斥","用AtomicInteger实现原子递增"],"tags":["volatile","内存屏障","可见性","原子性"],"id":2630},{"category":"java_advanced_choice","difficulty":"hard","type":"choice","title":"死锁的四个必要条件","content":"以下关于死锁四个必要条件的描述，哪一项是正确的？\n① 互斥条件：资源不能被共享\n② 请求与保持：线程持有资源的同时请求其他资源\n③ 不可剥夺：已分配的资源不能被强制剥夺\n④ 循环等待：存在一条循环等待链","options":["A) 只有①③④","B) 只有①②④","C) ①②③④全部是必要条件，缺少任何一个均不会发生死锁","D) 只有①②③"],"answer":"C","hints":["破坏任意必要条件即可打破死锁","数据库锁破坏不可剥夺条件防死锁","资源有序分配法破坏循环等待"],"tags":["deadlock","并发","锁","操作系统"],"id":2631},{"category":"java_advanced_choice","difficulty":"medium","type":"short_answer","title":"泛型通配符 PECS 原则","content":"给定 List<? extends Number> list1 和 List<? super Integer> list2，以下哪项操作可以编译通过？\nA) list1.add(Integer.valueOf(1))\nB) list2.add(Integer.valueOf(1))\nC) list1.add(new Object())\nD) list2.add(new Object())","answer":"B","hints":["extends 限定意味着生产者不能写入","super 限定意味着消费者可以安全写入"],"tags":["Java","泛型","PECS","通配符"],"id":2632},{"category":"java_advanced_choice","difficulty":"medium","type":"short_answer","title":"@Inherited 元注解的作用范围","content":"关于 @Inherited 元注解的行为，以下哪项描述是正确的？\nA) 父类上声明的所有注解都会自动被子类继承，无需额外标记\nB) @Inherited 使父类上的注解被子类继承，但仅对类层次继承有效，对接口实现和方法重写无效\nC) @Inherited 仅对接口继承有效，对类继承无效\nD) @Inherited 既支持类继承也支持方法重写时的注解继承","answer":"B","hints":["@Inherited 只沿类继承链传播","接口实现上的注解永远不被继承"],"tags":["Java","注解","@Inherited","元注解"],"id":2633},{"category":"java_advanced_choice","difficulty":"hard","type":"short_answer","title":"try-with-resources 的异常抑制机制","content":"关于 try-with-resources 的异常处理机制，以下哪项是正确的？\nA) 资源关闭时 close() 抛出的异常会覆盖 try 块中抛出的异常，导致原始异常丢失\nB) try 块和 close() 同时抛出异常时，两个异常都被传播但调用方只能捕获到 close() 异常\nC) close() 抛出的异常被添加到 try 块异常的抑制列表中，可通过 Throwable.getSuppressed() 获取\nD) try-with-resources 只能管理单个资源，多个资源需要嵌套 try 语句","answer":"C","hints":["抑制异常机制从 Java 7 开始引入","getSuppressed 返回的是 close 阶段产生的附加异常"],"tags":["Java","异常处理","try-with-resources"],"id":2634},{"category":"java_advanced_choice","difficulty":"hard","type":"short_answer","title":"VarHandle 的内存排序语义","content":"在 VarHandle 的四种内存排序访问模式中，以下哪项描述是正确的？\nA) set() 保证写操作立即对其他线程可见，等价于 volatile 写\nB) setRelease() 保证写之前的操作不会被重排序到写之后，但不保证其他线程能立即看到该写入\nC) getAcquire() 保证读之后的操作不会被重排序到读之前，且读到的值一定是某个线程写入的值\nD) getOpaque() 提供全局顺序一致性，等价于 volatile 读","answer":"C","hints":["release 和 acquire 是配对使用的内存屏障","plain 模式不做任何重排序限制"],"tags":["Java","VarHandle","内存排序","JMM"],"id":2635},{"category":"java_advanced_choice","difficulty":"hard","type":"short_answer","title":"MethodHandle.Lookup 的访问权限边界","content":"关于 MethodHandle.Lookup 的访问控制，以下哪项是正确的？\nA) 任意位置创建的 Lookup 对象可以访问所有类的所有方法，不受访问控制限制\nB) Lookup 对象持有创建者类的完整访问权限，可以访问模块内的 private 成员，但无法跨模块访问未导出包中的方法\nC) Lookup.findVirtual() 可以在任意类上查找 private 方法\nD) Lookup.unreflect() 可以将任意 Method 对象转换为 MethodHandle，无视访问权限检查","answer":"B","hints":["Lookup 的权限在创建时由调用者类决定","模块系统对 Lookup 的访问范围有额外限制"],"tags":["Java","MethodHandle","反射","模块系统"],"id":2636},{"category":"java_advanced_choice","difficulty":"hard","type":"short_answer","title":"StackWalker RETAIN_CLASS_REFERENCE 性能开销","content":"StackWalker API（JDK 9+）提供了两种获取实例的方式。关于 `StackWalker.getInstance()` 和 `StackWalker.getInstance(Option.RETAIN_CLASS_REFERENCE)` 之间的区别，以下哪项描述是正确的？\nA) 两者功能完全一致，RETAIN_CLASS_REFERENCE 仅用于在获取 StackFrame 时额外保留方法的 Class 引用，供后续反射调用使用\nB) 使用 RETAIN_CLASS_REFERENCE 的 StackWalker 可以获取 `StackFrame.getDeclaringClass()` 返回的 `Class<?>` 对象；不使用此选项则调用该方法会抛出 UnsupportedOperationException。RETAIN_CLASS_REFERENCE 的额外开销在于 SecurityManager 权限检查和 JVM 内部 Class 对象的解析\nC) RETAIN_CLASS_REFERENCE 仅影响 frames 的遍历速度，不影响返回的 StackFrame 对象的可用方法\nD) 不使用 RETAIN_CLASS_REFERENCE 的 StackWalker 不能调用 walk() 方法，只能调用 forEach()","answer":"B) 使用 RETAIN_CLASS_REFERENCE 选项的 StackWalker 允许调用 `StackFrame.getDeclaringClass()` 来获取 Class<?> 对象，而不使用该选项时此方法抛出 UnsupportedOperationException。RETAIN_CLASS_REFERENCE 额外的性能开销来自于：JVM 需要为每个 frame 加载和解析 Class 对象，这涉及类加载器的查找和可能触发的类加载——对于短生命周期的大量栈帧遍历场景，累计开销显著。","hints":["getDeclaringClass() 需要额外的 JVM 内部操作来解析 Class 引用，这是 RETAIN_CLASS_REFERENCE 的主要开销来源","如果不需要 Class 引用，使用默认的 StackWalker 可以避免类加载器查找和 Class 对象解析"],"tags":["stackwalker","stack-frame","class-reference","jep-259","performance"],"id":2637},{"category":"java_advanced_choice","difficulty":"hard","type":"short_answer","title":"VarHandle 内存排序模式选择","content":"VarHandle（JDK 9+）提供了四种内存排序访问模式：plain、opaque、acquire/release、volatile。以下关于这些模式的描述，哪项是正确的？\nA) plain 和 opaque 模式都保证原子性但不保证任何内存排序；acquire/release 保证线程间传递性；volatile 保证全排序（total order）\nB) opaque 模式既保证原子性又保证跨线程的可见性（立即对其他线程可见），但不阻止指令重排；plain 模式既不保证原子性也不保证排序\nC) opaque 模式保证原子性和同一个线程内的 bitwise 一致性，但不保证跨线程的可见性——其他线程可能永远看不到 opaque 的写入\nD) 所有四种模式都保证对引用类型和原始类型的原子性（连 long/double 也不例外），区别仅在于内存排序语义","answer":"C) opaque 模式（也称为「位一致」模式）保证：1) 原子性——对引用和所有原始类型包括 long/double 的读写都是原子的（plain 模式不保证 long/double 的原子性）2) 同一个线程内的 data-race-free 一致性——不会读到「撕裂值」(torn value) 3) 但 opaque 模式不保证跨线程的顺序和可见性——另一个线程可能无限期地看不到 opaque 写入的值。这是 JEP 193 定义的 varhandle 内存排序层级中最基础但最容易被误解的一层。","hints":["plain 模式不保证 long/double 的原子性（可能读到 torn value），但 opaque 保证所有类型的原子性","opaque 的关键特性是「自洽」——本线程看到的自己的写入顺序不变，但其他线程可能看不到"],"tags":["varhandle","memory-ordering","jep-193","opaque","atomics"],"id":2638},{"category":"java_advanced_choice","difficulty":"medium","type":"short_answer","title":"MethodHandle invoke 与 invokeExact 的区别","content":"MethodHandle（JDK 7+）提供了 invoke 和 invokeExact 两种调用方式。以下哪项正确描述了两者的区别？\nA) invoke 和 invokeExact 在功能上完全相同，invokeExact 只是 invoke 的别名，为了 API 可读性而存在\nB) invoke 允许 JVM 在调用时进行参数和返回值的类型适配（如装箱、拆箱、类型转换），而 invokeExact 要求调用点的类型签名与 MethodHandle 的类型签名完全匹配，否则抛出 WrongMethodTypeException\nC) invokeExact 比 invoke 性能差，因为 invokeExact 在每次调用时都要做完整的类型检查\nD) invoke 只能用在 invokeExact 不支持的场景中，即当方法句柄指向可变参数方法时","answer":"B) invoke 在调用时如果参数类型不完全匹配，JVM 会进行类型适配转换（包括引用类型的强制转换、基本类型的扩展/缩窄转换、装箱/拆箱等），然后执行调用。而 invokeExact 要求调用点的签名（包括参数类型和返回类型）与 MethodHandle 自身的 type() 完全匹配——如果不匹配，在调用时抛出 WrongMethodTypeException，不做任何自动适配。这种精确匹配让 JIT 可以做更激进的优化（如完全内联消除方法句柄调用），因此 invokeExact 性能通常优于 invoke。","hints":["invokeExact 不进行类型适配——调用前需要通过 MethodHandle.asType() 手动转换","JIT 对 invokeExact 的优化程度更高，因为类型在调用点就已完全确定"],"tags":["methodhandle","invoke","invokeexact","jep-277","reflection"],"id":2639},{"category":"java_advanced_choice","difficulty":"medium","type":"short_answer","title":"JPMS requires transitive 传递性规则","content":"在 Java Platform Module System（JPMS, JDK 9+）中，`requires transitive` 用于声明模块依赖的「隐式可读性」。以下关于其传递规则的描述，哪项是正确的？\nA) 模块 A `requires transitive B`，意味着 A 的传递依赖模块 C 自动获得对 B 的读取权限\nB) 模块 A `requires transitive B`，那么任何 `requires A` 的模块自动获得对 B 的读取权限（包括其 exported 包），无需显式 `requires B`\nC) requires transitive 的效果仅限于同一模块图内的编译期，运行期不生效\nD) requires transitive 只能应用于 java.base 模块，对自定义模块使用会导致模块系统不兼容","answer":"B) 这是 requires transitive 的核心语义。如果模块 A 声明 `requires transitive B`，那么任何读取 A 的模块会隐式地也读取 B。这典型用于：当 A 的 public API 的方法签名中暴露了 B 中的类型时，A 应该用 `requires transitive B`，这样使用 A 的模块不需要额外再写 `requires B` 就能使用这些类型。例如 java.sql 模块 `requires transitive java.xml`，所以使用 JDBC 的代码可以直接使用 org.xml 包中的类型而无需显式 requires。","hints":["需要 transitive 的关键判断是：我的 API 是否在 public 方法签名中暴露了依赖模块的类型？","不恰当地使用 requires transitive 会导致不必要的传递依赖，增加模块耦合"],"tags":["jpms","module-system","requires-transitive","encapsulation","java-9"],"id":2640},{"category":"java_advanced_choice","difficulty":"hard","type":"short_answer","title":"动态 CDS 存档内容范围","content":"JDK 13+（JEP 350）引入了动态 CDS（Class Data Sharing）存档功能，允许在应用退出时自动创建归档。关于动态 CDS 存档的内容范围，以下哪项描述是正确的？\nA) 动态 CDS 存档只包含 JDK 内置类（如 java.lang.String），不包含应用的类\nB) 动态 CDS 存档在应用退出时自动捕获所有已加载的类（包括应用类和库类），但默认存档路径是临时目录，不会影响后续启动\nC) 动态 CDS 存档通过 `-XX:ArchiveClassesAtExit` 指定输出路径，存档内容包含应用运行过程中加载的所有非布尔类（non-boolean classes），并在后续启动时通过 `-XX:SharedArchiveFile` 加载以提升启动速度\nD) 动态 CDS 存档与 AppCDS 完全独立，二者不能同时使用","answer":"C) 动态 CDS 存档通过在 JVM 退出时使用 `-XX:ArchiveClassesAtExit=<path>` 生成。存档内容包含：app class loader 加载的所有类 + platform class loader 和 bootstrap class loader 加载的类（排除布尔类、已存档在静态 CDS 中的类等）。后续启动时通过 `-XX:SharedArchiveFile=<path>` 加载，JVM 会验证存档的兼容性（如类路径是否匹配），兼容时直接从共享内存映射加载类，跳过类文件解析和验证阶段，显著减少启动时间和内存占用。","hints":["动态 CDS 的核心价值在于免去了手动 dump class list 和创建 archive 的 AppCDS 三步流程","使用动态 CDS 时 JVM 会自动检测类路径变化并 fallback 到非存档模式，保证不会因存档不兼容而启动失败"],"tags":["cds","appcds","class-data-sharing","jep-350","startup-performance"],"id":2641},{"category":"java_advanced_choice","difficulty":"hard","type":"short_answer","title":"ConstantDynamic (Condy) 引导方法调用的缓存时机","content":"关于 ConstantDynamic (Condy) 引导方法调用的时机和缓存行为，以下哪项描述是正确的？\nA) 引导方法在 JVM 启动阶段对所有 Condy 常量执行批量调用\nB) 引导方法在包含 Condy 的类被链接（linking）时执行，结果缓存在运行时常量池\nC) 引导方法在 CONSTANT_Dynamic 条目首次被字节码指令实际访问时执行，结果被 JVM 缓存\nD) 引导方法在每次包含 Condy 的字段或方法被访问时都重新执行","answer":"C) ConstantDynamic 的引导方法采用懒解析（lazy resolution）策略。只有当 CONSTANT_Dynamic 常量池条目首次被某条字节码指令实际访问时，JVM 才调用对应的 bootstrap method。引导方法返回的值被缓存在运行时常量池中，此后所有对该 Condy 常量的访问都直接返回缓存值，不会再次调用引导方法。这与 invokedynamic 的引导方法行为类似，区别在于 Condy 返回的是常量值而非 CallSite 对象。","hints":["Condy 的懒解析语义意味着从未被实际使用的 Condy 条目永远不会触发引导方法调用，这在应用启动性能上有优势","Condy 与 invokedynamic 共享 BootstrapMethods 属性，但解析后的缓存粒度不同：Condy 缓存结果值，invokedynamic 缓存 CallSite"],"tags":["ConstantDynamic","Condy","引导方法","懒解析","常量池"],"options":[],"company":"","id":2642},{"category":"java_advanced_choice","difficulty":"medium","type":"short_answer","title":"ForkJoinPool.commonPool 默认并行度计算规则","content":"ForkJoinPool.commonPool() 在未显式设置 parallelism 参数时，其默认并行度是如何确定的？\nA) Runtime.getRuntime().availableProcessors()，即 CPU 核心数\nB) Runtime.getRuntime().availableProcessors() - 1，即 CPU 核心数减一\nC) Math.max(2, availableProcessors())，最少为 2\nD) 始终为 4，与 CPU 核心数无关","answer":"B) ForkJoinPool.commonPool() 的默认并行度为 Runtime.getRuntime().availableProcessors() - 1，最小值为 1（单核 CPU 上为 1）。设计理由：ForkJoinPool 用于 CPU 密集型并行计算，预留一个核心给调用线程或其他系统任务使用。当 availableProcessors() 返回 1（单核环境）时，并行度为 1，即所有任务在调用线程中串行执行。可通过系统属性 java.util.concurrent.ForkJoinPool.common.parallelism 覆盖此默认值。","hints":["commonPool 的并行度与虚拟线程的 carrier 线程池（ForkJoinPool）不同——虚拟线程调度使用不同的 ForkJoinPool，其并行度通常等于 availableProcessors()","通过 -Djava.util.concurrent.ForkJoinPool.common.parallelism=N 可覆盖默认并行度"],"tags":["ForkJoinPool","commonPool","并行度","线程池","并发"],"options":[],"company":"","id":2643},{"category":"java_advanced_choice","difficulty":"hard","type":"short_answer","title":"基于值的类在 JDK 16+ 的同步限制","content":"JDK 16（JEP 390）对基于值的类（Value-Based Class）的同步操作进行了强制限制。以下哪项描述了这一限制的具体行为？\nA) 仅产生编译警告，运行时不产生任何影响\nB) 编译时报错，拒绝编译对基于值的类进行 synchronized 的代码\nC) 运行时抛出 IllegalMonitorAccessException 或类似异常\nD) 编译器和运行期都静默忽略 synchronized 块","answer":"C) JDK 16（JEP 390）将对基于值的类（Value-Based Class）的同步操作（synchronized 块或 synchronized 方法）从编译警告升级为运行时抛出 IllegalMonitorStateException。Value-Based Class 包括 java.util.Optional、java.time.LocalDate、java.math.BigInteger 等，它们被设计为不可变的、无标识的（identity-less）值对象。未来 Project Valhalla 的 primitive class 将无法进行同步，提前施加限制是为了防止依赖同步行为的代码在值类型迁移后出现静默错误。","hints":["通过 jdk.internal.ValueBased 注解标记哪些类是 value-based class，运行时同步检测基于该注解","常用的 value-based class：LocalDate、LocalDateTime、Optional、BigInteger、Instant、Period 等"],"tags":["Value-Based Class","JEP 390","同步限制","Valhalla","值类型"],"options":[],"company":"","id":2644},{"category":"java_advanced_choice","difficulty":"medium","type":"short_answer","title":"Lookup.defineClass 与 ClassLoader.defineClass 的核心权限区别","content":"关于 MethodHandles.Lookup.defineClass（JDK 9+）与 ClassLoader.defineClass 在类定义权限上的核心区别，以下哪项描述是正确的？\nA) Lookup.defineClass 可以定义任意包中的类，而 ClassLoader.defineClass 只能在 caller 的包中定义\nB) ClassLoader.defineClass 不需要字节码参数，可以直接从类名加载\nC) Lookup.defineClass 只能在 Lookup 对象所在类的同一模块中定义类，且不触发类链接的完整流程\nD) Lookup.defineClass 与 ClassLoader.defineClass 功能完全相同","answer":"C) Lookup.defineClass 的方法签名是 MethodHandles.Lookup.defineClass(byte[] bytes)，它只能在 Lookup 对象所在类的同一模块中定义类。该方法的限制：目标类必须在同一运行期包（runtime package）中，且不触发完整的类链接流程（即类被定义但未被完全解析和初始化）。相比之下，ClassLoader.defineClass 更灵活——可以将类定义到任意包中（受 SecurityManager 约束），并触发完整的类加载和链接流程。Lookup.defineClass 的主要优势是更轻量——它不需要经过 ClassLoader 的 findClass/loadClass 循环，直接在 Lookup 的上下文中定义类，适合在 Lambda 表达式和动态代理等需要快速定义小类的场景中使用。","hints":["Lookup.defineClass 定义的类不能包含包名称与 Lookup 所在类不同的包","Lookup.defineClass 返回的 Class 对象尚未经过验证和准备阶段——它仅在被首次使用时才触发链接"],"tags":["Lookup.defineClass","ClassLoader","类定义","模块系统","动态代理"],"options":[],"company":"","id":2645},{"category":"java_advanced_choice","difficulty":"hard","type":"short_answer","title":"JVM TI RetransformClasses 对已加载方法的替换时机","content":"JVM TI（Tool Interface）的 RetransformClasses 函数用于重新变换已经加载的类。关于该方法替换后对正在执行的方法的影响，以下哪项描述是正确的？\nA) 重新变换后，当前所有已激活栈帧中的方法字节码被立即替换\nB) 已在栈上执行的方法继续运行原始字节码，新调用使用变换后的版本\nC) 在最近的安全点（SafePoint）对所有活跃方法执行 OSR（On-Stack Replacement）替换\nD) 重新变换仅在下次 JVM 重启后生效","answer":"B) 根据 JVMS 和 JVM TI 规范，RetransformClasses 对已加载类进行字节码变换后，当前已经在调用栈上执行的方法（活动栈帧）继续运行变换前的原始字节码。对于这些方法的新调用（后续的重新进入），将使用变换后的字节码。这与常规模块类替换的逻辑一致——方法体被替换但不影响正在执行的调用。如果要影响当前正在执行的代码，需要结合支持栈上替换（OSR）的特定工具更为复杂的处理。提示：RetransformClasses 不能添加/移除字段或方法，只能修改方法体。","hints":["RetransformClasses 只能修改方法体（Method body），不能增加/删除字段、方法或修改类签名","重变换的关键应用场景包括 APM（应用性能监控）的字节码插桩、AOP 框架的热替换"],"tags":["JVM TI","RetransformClasses","字节码","代理","热替换"],"options":[],"company":"","id":2646}];
